func TestUpdateBalanceWETHToUSDC(t *testing.T) {
	t.Parallel()
	sim := mustNewSim(t, wethUSDCPool)

	res, err := sim.CalcAmountOut(pool.CalcAmountOutParams{
		TokenAmountIn: pool.TokenAmount{
			Token:  "0xc02aaa39b223fe8d0a0e5c4f27ead9083c756cc2",
			Amount: bignum.NewBig("70000000100000000"),
		},
		TokenOut: "0xa0b86991c6218b36c1d19d4a2e9eb0ce3606eb48",
	})
	require.NoError(t, err)

	sim.UpdateBalance(pool.UpdateBalanceParams{
		TokenAmountIn: pool.TokenAmount{
			Token:  "0xc02aaa39b223fe8d0a0e5c4f27ead9083c756cc2",
			Amount: bignum.NewBig("70000000100000000"),
		},
		TokenAmountOut: *res.TokenAmountOut,
		Fee:            *res.Fee,
		SwapInfo:       res.SwapInfo,
	})

	// After the swap, the USDC liquidity should be reduced — a second quote for the
	// same amount must not exceed what's left in the pool.
	res2, err := sim.CalcAmountOut(pool.CalcAmountOutParams{
		TokenAmountIn: pool.TokenAmount{
			Token:  "0xc02aaa39b223fe8d0a0e5c4f27ead9083c756cc2",
			Amount: bignum.NewBig("70000000100000000"),
		},
		TokenOut: "0xa0b86991c6218b36c1d19d4a2e9eb0ce3606eb48",
	})
	if err == nil {
		require.True(t, res2.TokenAmountOut.Amount.Cmp(res.TokenAmountOut.Amount) <= 0,
			"second quote should not exceed first after UpdateBalance")
	}
}
